#include <iostream>
using namespace std;
int fun(int x,int y)
{
    if(x==1||y==1||x==0)
    {
        return 1;
    }
    else if(x<y)
    {
        return fun(x,x);
    }
    else
    {
        return fun(x-y,y)+fun(x,y-1);
    }
}
int main()
{
    int t,m,n;
    cin>>t;
    for(int i=0;i<=t-1;i++)
    {
        cin>>m>>n;
        cout<<fun(m,n)<<endl;
    }
    return 0;
}
